svg.script:
let ws = new WebSocket("ws://127.0.0.1:8000/ws")

ws.onmessage = (e)=>{
 let data = JSON.parse(e.data)

 // status
 document.getElementById("status").textContent = data.status || "idle"
 document.getElementById("merkle").textContent = data.merkle || "none"

 // history log
 let log = data.history.slice(-6)
 document.getElementById("log").textContent =
   log.map(x=>x.timestamp+" | "+x.status).join("\n")

 // agents
 let g = document.getElementById("agents")
 let links = document.getElementById("links")
 g.innerHTML = ""
 links.innerHTML = ""

 let i=0
 for(let k in data.agents){

  let angle = (i / Object.keys(data.agents).length) * Math.PI*2
  let x = 800 + Math.cos(angle)*250
  let y = 400 + Math.sin(angle)*250

  // node
  g.innerHTML += `
   <circle cx="${x}" cy="${y}" r="25" fill="#00ffff" filter="url(#glow)">
    <animate attributeName="r" values="20;30;20" dur="2s" repeatCount="indefinite"/>
   </circle>
   <text x="${x-30}" y="${y+50}" fill="#ffffff">${k}</text>
  `

  // link to core
  links.innerHTML += `
   <line x1="800" y1="400" x2="${x}" y2="${y}" stroke="#00ffff" opacity="0.3">
    <animate attributeName="opacity" values="0.2;0.8;0.2" dur="2s" repeatCount="indefinite"/>
   </line>
  `

  i++
 }
}

ws.onerror = ()=>{
 document.getElementById("status").textContent = "OFFLINE"
}
